import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Table, Button } from "react-bootstrap";
import axios from "axios";

const ListOfDrugs = () => {
  const [drugs, setDrugs] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    // Gọi API để lấy danh sách thuốc
    axios.get("/api/drugs")
      .then((response) => setDrugs(response.data))
      .catch((error) => console.error("Lỗi khi lấy danh sách thuốc:", error));
  }, []);

  const handleEdit = (id) => {
    navigate(`/editDrug/${id}`);
  };

  return (
    <div className="container mt-4">
      <h2>Danh Sách Thuốc</h2>
      <Table striped bordered hover>
        <thead>
          <tr>
            <th>#</th>
            <th>Tên Thuốc</th>
            <th>Loại Thuốc</th>
            <th>Giá</th>
            <th>Hành động</th>
          </tr>
        </thead>
        <tbody>
          {drugs.map((drug, index) => (
            <tr key={drug.id}>
              <td>{index + 1}</td>
              <td>{drug.name}</td>
              <td>{drug.type}</td>
              <td>{drug.price} VNĐ</td>
              <td>
                <Button variant="warning" onClick={() => handleEdit(drug.id)}>
                  Sửa
                </Button>
                &nbsp;
                <Button variant="danger">Xóa</Button>
              </td>
            </tr>
          ))}
        </tbody>
      </Table>
    </div>
  );
};

export default ListOfDrugs;
